<template>
  <div class="tool">
		<h1>工具</h1>
    <ul class="us container">
      <li v-for="(item,index) in tools" :key="index" class="item-box">
        <h2 style="margin-top: 50px;">{{item.title}}</h2>
        <h4 style="text-align: left;margin-top: 30px;">{{item.sunTitle}}</h4>
        <h5 class="text-pre-wrap" style="text-align: left; color: #a3a3a3;margin-top: 40px;">{{item.desc}}</h5>
        <!-- <img src="../../../static/img/tools/doubleCircle.png" alt=""> -->
      </li>
    </ul>
  </div>
</template>
<script>
export default {
  name: "tool",
  data() {
    return {
      tools: [
        {
          title: "API工具",
          sunTitle: "通过API工具集成我们的代理ip，可以使用任何通用的编码语言。我们提供预demo例子，在账户管理页面查相关文档。",
          desc: "简单易用：使用为您的代码访问LucproxyAPI，只需选择您的首选设置，灵活使用\n\n功能强大：支持指定国家地区访问，支持多请求并发处理，超级稳定\n\n集成任何系统：Lucproxy业务API可以与任何机器人，爬虫或现有的接口无缝对接"
        },
        {
          title: "Lucproxy客户端",
          sunTitle: "一个前端开源代理管理器，可以使您自定义场景开发，可以加快开发和部署时间。",
          desc: "允许自定义规则，灵活使用手机IP、住宅IP、机房数据中心IP网络，满足更深层业务需求。\n\n集成任何系统：Lucproxy业务API可以与任何机器人，爬虫或现有的接口无缝对接"
        },
        {
          title: "Chrome插件",
          sunTitle: "在Chrome浏览器的工具栏页面安装插件，即可快速实现IP使用，很轻松实现动态、静态IP、机房数据中心的快速使用",
          desc: "允许自定义规则，灵活使用手机IP、住宅IP、机房数据中心IP网络，满足更深层业务需求。\n\n集成任何系统：Lucproxy业务API可以与任何机器人，爬虫或现有的接口无缝对接"
        }
      ]
    };
  },
  created() {
    this.$emit("headFix", ["relative", false, "rgba(3,3,3,.8)"]);
  },
  methods: {}
};
</script>
<style lang="scss" scoped>

.tool {
	padding-top: 5%;
  background-color: rgb(242, 243, 248);
  .us {
    display: flex;
    justify-content: center;
    padding: 3% 0 10%;
    .item-box{
      position: relative;
      padding: 30px 30px;
      width: 250px;
      min-height: 300px;
      border: 0.5px solid rgba(0, 0, 0, 0.101961);
      border-radius: 5px;
      background-color: white;
      &:nth-of-type(n+2){
        margin-left: 1.25rem;
      }
      img{
        position: absolute;
        top: 30px;
        right: 30px;
      }
    }
  }
}
// 动画
@keyframes self-zoomIn {
  from {
    border: 0px solid transparent;
    transform: scale3d(0.3, 0.3, 0.3);
  }

  50% {
    border: 3px solid #ffffff;
  }

  80% {
    border: 3px solid #ffffff;
  }

  100% {
    border: 3px solid rgba(255, 255, 255, 0.4);
  }
}
</style>



